document.addEventListener("DOMContentLoaded",function(e){initVal(1e3,800,18,118,1200);calcQuantity(e);document.getElementById("recipeCalculator").addEventListener("submit",calcQuantity)});function calcQuantity(e){e.preventDefault();const baseRecipeForm=document.getElementById("recipeCalculator");const formData=new FormData(baseRecipeForm);const flourBase=parseInt(formData.get("flourBase"));const waterBase=parseInt(formData.get("waterBase"));const sourdoughBase=parseInt(formData.get("sourdoughBase"));const saltBase=parseInt(formData.get("saltBase"));const sumBase=flourBase+waterBase+sourdoughBase+saltBase;document.getElementById("sumBase").innerHTML=sumBase;document.getElementById("hydrationRate").innerHTML=Math.round(waterBase/flourBase*1e4)/100;document.getElementById("sourdoughRate").innerHTML=Math.round(sourdoughBase/sumBase*1e4)/100;const multiplier=Math.round(parseInt(formData.get("wanted"))/sumBase*100)/100;const flourRequired=Math.round(flourBase*multiplier);const waterRequired=Math.round(waterBase*multiplier);const sourdoughRequired=Math.round(sourdoughBase*multiplier);const saltRequired=Math.round(saltBase*multiplier);document.getElementById("multiplier").innerHTML=multiplier;document.getElementById("flourRequired").innerHTML=flourRequired;document.getElementById("waterRequired").innerHTML=waterRequired;document.getElementById("sourdoughRequired").innerHTML=sourdoughRequired;document.getElementById("saltRequired").innerHTML=saltRequired;document.getElementById("sumRequired").innerHTML=Math.round(flourRequired+waterRequired+sourdoughRequired+saltRequired)}function initVal(flour,water,salt,sourdough,wanted){document.getElementById("flourBase").value=flour;document.getElementById("waterBase").value=water;document.getElementById("saltBase").value=salt;document.getElementById("sourdoughBase").value=sourdough;document.getElementById("wanted").value=wanted}